    (12,16,50,"tests/realtime/test_spectrogram_buf.py",'"""Tests for spectrogram buffer."""\nimport numpy as np\nfrom bird_mach.realtime.spectrogram_buffer import SpectrogramBuffer\nclass TestSpectrogramBuffer:\n    def test_push(self):\n        buf = SpectrogramBuffer(n_frames=10, n_bins=32)\n        buf.push(np.zeros(32))\n        assert buf.frame_count == 1\n    def test_get_image(self):\n        buf = SpectrogramBuffer(n_frames=5, n_bins=16)\n        for _ in range(3):\n            buf.push(np.random.randn(16).astype(np.float32))\n        img = buf.get_image()\n        assert img.shape == (16, 3)\n',"test(realtime): add spectrogram buffer tests"),
    (12,17,15,"bird_mach/realtime/noise_gate.py",'"""Real-time noise gate."""\nfrom __future__ import annotations\nimport numpy as np\n\nclass NoiseGate:\n    """Simple noise gate that mutes signal below a threshold."""\n    def __init__(self, threshold_db: float = -40.0, attack_ms: float = 1.0, release_ms: float = 50.0):\n        self._threshold = 10 ** (threshold_db / 20)\n        self._attack = attack_ms\n        self._release = release_ms\n        self._open = False\n\n    def process(self, samples: np.ndarray) -> np.ndarray:\n        rms = float(np.sqrt(np.mean(samples ** 2)))\n        if rms > self._threshold:\n            self._open = True\n        elif rms < self._threshold * 0.7:\n            self._open = False\n        return samples if self._open else samples * 0.01\n\n    @property\n    def is_open(self) -> bool:\n        return self._open\n',"feat(realtime): add noise gate for live audio"),
    (12,17,40,"bird_mach/realtime/level_meter.py",'"""Multi-channel level metering."""\nfrom __future__ import annotations\nimport numpy as np\nfrom dataclasses import dataclass\n\n@dataclass\nclass LevelReading:\n    rms_db: float\n    peak_db: float\n    clip: bool\n\nclass LevelMeter:\n    """VU-style level meter with peak hold."""\n    def __init__(self, clip_db: float = -0.5):\n        self._clip_db = clip_db\n        self._peak_hold = -100.0\n\n    def read(self, samples: np.ndarray) -> LevelReading:\n        rms = float(np.sqrt(np.mean(samples ** 2)))\n        peak = float(np.max(np.abs(samples)))\n        rms_db = 20 * np.log10(rms + 1e-10)\n        peak_db = 20 * np.log10(peak + 1e-10)\n        self._peak_hold = max(self._peak_hold * 0.995, peak_db)\n        return LevelReading(rms_db=rms_db, peak_db=peak_db, clip=peak_db > self._clip_db)\n',"feat(realtime): add VU-style level meter with peak hold"),
    (12,18,5,"bird_mach/realtime/tuner.py",'"""Real-time chromatic tuner."""\nfrom __future__ import annotations\nimport numpy as np\n\nNOTE_NAMES = ["C","C#","D","D#","E","F","F#","G","G#","A","A#","B"]\n\nclass ChromaticTuner:\n    """Detect the closest musical note and cents deviation."""\n    def __init__(self, a4_hz: float = 440.0):\n        self._a4 = a4_hz\n\n    def tune(self, freq_hz: float) -> dict:\n        if freq_hz <= 0:\n            return {"note": "—", "octave": 0, "cents": 0.0, "freq": 0.0}\n        semitones = 12 * np.log2(freq_hz / self._a4)\n        midi = round(semitones) + 69\n        note = NOTE_NAMES[midi % 12]\n        octave = (midi // 12) - 1\n        cents = (semitones - round(semitones)) * 100\n        return {"note": note, "octave": octave, "cents": round(cents, 1), "freq": round(freq_hz, 1)}\n',"feat(realtime): add chromatic tuner for live pitch display"),
    (12,18,30,"bird_mach/realtime/key_detector.py",'"""Musical key detection from chroma features."""\nfrom __future__ import annotations\nimport numpy as np\n\nKEY_PROFILES = {\n    "major": [6.35,2.23,3.48,2.33,4.38,4.09,2.52,5.19,2.39,3.66,2.29,2.88],\n    "minor": [6.33,2.68,3.52,5.38,2.60,3.53,2.54,4.75,3.98,2.69,3.34,3.17],\n}\n\nclass KeyDetector:\n    """Detect musical key using Krumhansl-Schmuckler algorithm."""\n    def detect(self, chroma: np.ndarray) -> dict:\n        if chroma.ndim == 2:\n            chroma = np.mean(chroma, axis=1)\n        chroma = chroma[:12]\n        best_key, best_corr, best_mode = "C", -1.0, "major"\n        notes = ["C","C#","D","D#","E","F","F#","G","G#","A","A#","B"]\n        for mode, profile in KEY_PROFILES.items():\n            prof = np.array(profile)\n            for i in range(12):\n                rolled = np.roll(chroma, -i)\n                corr = float(np.corrcoef(rolled, prof)[0, 1])\n                if corr > best_corr:\n                    best_corr, best_key, best_mode = corr, notes[i], mode\n        return {"key": best_key, "mode": best_mode, "confidence": round(best_corr, 3)}\n',"feat(realtime): add musical key detection (Krumhansl-Schmuckler)"),
    (12,19,0,"bird_mach/realtime/tempo_estimator.py",'"""Real-time tempo estimation via autocorrelation of onset envelope."""\nfrom __future__ import annotations\nimport numpy as np\nfrom collections import deque\n\nclass TempoEstimator:\n    """Estimate tempo from streaming onset strength values."""\n    def __init__(self, sr: int = 44100, hop: int = 512):\n        self._sr = sr\n        self._hop = hop\n        self._onset_buf = deque(maxlen=500)\n\n    def feed(self, onset_strength: float) -> None:\n        self._onset_buf.append(onset_strength)\n\n    @property\n    def bpm(self) -> float:\n        if len(self._onset_buf) < 100:\n            return 0.0\n        data = np.array(self._onset_buf)\n        corr = np.correlate(data, data, mode="full")\n        corr = corr[len(corr)//2:]\n        bpm_min, bpm_max = 60, 200\n        min_lag = int(60 * self._sr / (self._hop * bpm_max))\n        max_lag = int(60 * self._sr / (self._hop * bpm_min))\n        search = corr[min_lag:max_lag]\n        if len(search) == 0:\n            return 0.0\n        best_lag = np.argmax(search) + min_lag\n        return 60 * self._sr / (self._hop * best_lag)\n',"feat(realtime): add streaming tempo estimation via autocorrelation"),
    (12,19,30,"bird_mach/realtime/dynamics.py",'"""Dynamic range analysis for real-time audio."""\nfrom __future__ import annotations\nimport numpy as np\nfrom collections import deque\n\nclass DynamicsAnalyzer:\n    """Track dynamic range statistics over a sliding window."""\n    def __init__(self, window_size: int = 100):\n        self._peaks = deque(maxlen=window_size)\n        self._rms_vals = deque(maxlen=window_size)\n\n    def update(self, samples: np.ndarray) -> dict:\n        peak = float(np.max(np.abs(samples)))\n        rms = float(np.sqrt(np.mean(samples**2)))\n        self._peaks.append(peak)\n        self._rms_vals.append(rms)\n        crest = peak / (rms + 1e-10)\n        dr = 20 * np.log10(max(self._peaks) / (np.mean(list(self._rms_vals)) + 1e-10))\n        return {"peak": peak, "rms": rms, "crest_factor": crest, "dynamic_range_db": float(dr)}\n',"feat(realtime): add dynamic range analyzer for live monitoring"),
    (12,20,0,"docs/enterprise/realtime-api.md",'# Real-Time API Reference\n\n## Engine\n```python\nengine = RealtimeEngine(EngineConfig(buffer_size=4096))\nawait engine.start()\nresult = await engine.process_frame(frame)\nawait engine.stop()\n```\n\n## DSP\n```python\nbands = compute_fft_bands(spectrum, sr=44100)\nwindowed = apply_window(samples, "hann")\nfb = mel_filterbank(sr=22050, n_fft=2048, n_mels=40)\n```\n\n## WebSocket\n```python\nmgr = AudioWebSocketManager(max_clients=100)\nclient = mgr.register("client-1", time.time())\nmgr.subscribe("client-1", "audio")\nawait mgr.broadcast("audio", data)\n```\n',"docs: add real-time API reference"),
    (12,20,30,"bird_mach/realtime/analyzer_chain.py",'"""Chain multiple real-time analyzers together."""\nfrom __future__ import annotations\nimport numpy as np\nfrom typing import Protocol\n\nclass RealtimeAnalyzer(Protocol):\n    def analyze(self, samples: np.ndarray, sr: int) -> dict: ...\n\nclass AnalyzerChain:\n    """Run multiple analyzers on each audio frame."""\n    def __init__(self):\n        self._analyzers: list[tuple[str, RealtimeAnalyzer]] = []\n\n    def add(self, name: str, analyzer: RealtimeAnalyzer) -> None:\n        self._analyzers.append((name, analyzer))\n\n    def process(self, samples: np.ndarray, sr: int) -> dict:\n        results = {}\n        for name, analyzer in self._analyzers:\n            results[name] = analyzer.analyze(samples, sr)\n        return results\n\n    @property\n    def analyzer_count(self) -> int:\n        return len(self._analyzers)\n',"feat(realtime): add analyzer chain for multi-analysis pipeline"),
    (12,21,0,"bird_mach/realtime/audio_router.py",'"""Route audio between multiple sources and destinations."""\nfrom __future__ import annotations\nimport numpy as np\n\nclass AudioRouter:\n    """Route audio frames between sources, effects, and outputs."""\n    def __init__(self):\n        self._routes: dict[str, list[str]] = {}\n        self._gains: dict[str, float] = {}\n\n    def connect(self, source: str, dest: str, gain: float = 1.0) -> None:\n        self._routes.setdefault(source, []).append(dest)\n        self._gains[f"{source}->{dest}"] = gain\n\n    def disconnect(self, source: str, dest: str) -> None:\n        if source in self._routes:\n            self._routes[source] = [d for d in self._routes[source] if d != dest]\n\n    def get_destinations(self, source: str) -> list[str]:\n        return self._routes.get(source, [])\n\n    def get_gain(self, source: str, dest: str) -> float:\n        return self._gains.get(f"{source}->{dest}", 1.0)\n',"feat(realtime): add audio router for flexible signal flow"),

