    (14,15,0,"bird_mach/plugin_system/effect_params.py",'"""Parameterized effect configuration with validation."""\nfrom __future__ import annotations\nfrom dataclasses import dataclass\n\n@dataclass\nclass ParamSpec:\n    name: str\n    min_val: float\n    max_val: float\n    default: float\n    unit: str = ""\n\n    def validate(self, value: float) -> float:\n        return max(self.min_val, min(self.max_val, value))\n\nGAIN_PARAM = ParamSpec("gain", -60.0, 24.0, 0.0, "dB")\nCUTOFF_PARAM = ParamSpec("cutoff", 20.0, 20000.0, 5000.0, "Hz")\nRATIO_PARAM = ParamSpec("ratio", 1.0, 20.0, 4.0, ":1")\nDECAY_PARAM = ParamSpec("decay", 0.0, 1.0, 0.3, "")\nDELAY_PARAM = ParamSpec("delay", 1.0, 500.0, 40.0, "ms")\n',"feat(plugins): add parameterized effect specs with validation"),
    (14,15,30,"bird_mach/reporting/html_report.py",'"""HTML report generation with embedded charts."""\nfrom __future__ import annotations\nfrom bird_mach.reporting.pdf_report import AnalysisReport\n\nclass HTMLReportRenderer:\n    """Render AnalysisReport as a styled HTML page."""\n    def render(self, report: AnalysisReport) -> str:\n        sections = ""\n        for s in report._sections:\n            sections += f"<section><h2>{s.title}</h2><p>{s.content}</p></section>\\n"\n        return f"""<!DOCTYPE html>\n<html><head><title>{report.title}</title>\n<style>body{{font-family:system-ui;background:#0f172a;color:#e2e8f0;max-width:800px;margin:0 auto;padding:2rem}}\nh1{{color:#38bdf8}}h2{{color:#818cf8;border-bottom:1px solid #334155;padding-bottom:0.5rem}}\nsection{{margin:1.5rem 0}}</style></head>\n<body><h1>{report.title}</h1>\n<p><em>Generated by {report.author}</em></p>\n{sections}</body></html>"""\n',"feat(reporting): add HTML report renderer with dark theme styling"),
    (14,16,0,"tests/reporting/test_html_report.py",'"""Tests for HTML report renderer."""\nfrom bird_mach.reporting.pdf_report import AnalysisReport\nfrom bird_mach.reporting.html_report import HTMLReportRenderer\nclass TestHTMLRenderer:\n    def test_render(self):\n        r = AnalysisReport("Test")\n        r.add_section("Intro", "Hello")\n        html = HTMLReportRenderer().render(r)\n        assert "<h1>Test</h1>" in html\n        assert "Hello" in html\n',"test(reporting): add HTML report renderer tests"),
    (14,16,30,"bird_mach/reporting/comparison_report.py",'"""Generate comparison reports between two audio files."""\nfrom __future__ import annotations\nfrom bird_mach.reporting.pdf_report import AnalysisReport\nfrom bird_mach.analysis import AnalysisSummary\n\ndef build_comparison_report(name_a: str, summary_a: AnalysisSummary,\n                            name_b: str, summary_b: AnalysisSummary) -> AnalysisReport:\n    report = AnalysisReport(f"Comparison: {name_a} vs {name_b}")\n    report.add_section("Overview", f"Comparing {name_a} ({summary_a.duration_s:.1f}s) with {name_b} ({summary_b.duration_s:.1f}s)")\n    tempo_diff = summary_b.tempo_bpm - summary_a.tempo_bpm\n    report.add_section("Tempo", f"{name_a}: {summary_a.tempo_bpm:.1f} BPM | {name_b}: {summary_b.tempo_bpm:.1f} BPM | Diff: {tempo_diff:+.1f}")\n    energy_diff = summary_b.rms_mean - summary_a.rms_mean\n    report.add_section("Energy", f"{name_a}: {summary_a.rms_mean:.4f} | {name_b}: {summary_b.rms_mean:.4f} | Diff: {energy_diff:+.4f}")\n    return report\n',"feat(reporting): add comparison report builder for A/B analysis"),
