    (14,17,30,"bird_mach/reporting/export_formats.py",'"""Export analysis data in various formats."""\nfrom __future__ import annotations\nimport json\nimport csv\nfrom io import StringIO\n\ndef to_json_lines(records: list[dict]) -> str:\n    return "\\n".join(json.dumps(r, default=str) for r in records)\n\ndef to_csv_string(records: list[dict]) -> str:\n    if not records:\n        return ""\n    buf = StringIO()\n    writer = csv.DictWriter(buf, fieldnames=records[0].keys())\n    writer.writeheader()\n    writer.writerows(records)\n    return buf.getvalue()\n\ndef to_tsv_string(records: list[dict]) -> str:\n    if not records:\n        return ""\n    buf = StringIO()\n    writer = csv.DictWriter(buf, fieldnames=records[0].keys(), delimiter="\\t")\n    writer.writeheader()\n    writer.writerows(records)\n    return buf.getvalue()\n',"feat(reporting): add JSONL, CSV, TSV export format helpers"),
    (14,18,0,"bird_mach/reporting/scheduled_reports.py",'"""Scheduled report generation configuration."""\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom enum import Enum\n\nclass Schedule(Enum):\n    DAILY = "daily"\n    WEEKLY = "weekly"\n    MONTHLY = "monthly"\n\n@dataclass\nclass ScheduledReport:\n    name: str\n    schedule: Schedule\n    recipients: list[str]\n    query: str\n    format: str = "html"\n    enabled: bool = True\n\nclass ReportScheduler:\n    def __init__(self):\n        self._schedules: list[ScheduledReport] = []\n\n    def add(self, report: ScheduledReport) -> None:\n        self._schedules.append(report)\n\n    def get_due(self, schedule: Schedule) -> list[ScheduledReport]:\n        return [r for r in self._schedules if r.schedule == schedule and r.enabled]\n\n    @property\n    def count(self) -> int:\n        return len(self._schedules)\n',"feat(reporting): add scheduled report configuration and scheduler"),
