    (15,17,0,"bird_mach/dashboard/alerts.py",'"""Alert rules and notification triggers."""\nfrom __future__ import annotations\nfrom dataclasses import dataclass\nfrom enum import Enum\n\nclass AlertSeverity(Enum):\n    INFO = "info"\n    WARNING = "warning"\n    CRITICAL = "critical"\n\n@dataclass\nclass AlertRule:\n    name: str\n    metric: str\n    threshold: float\n    severity: AlertSeverity\n    enabled: bool = True\n\nclass AlertManager:\n    def __init__(self):\n        self._rules: list[AlertRule] = []\n        self._fired: list[dict] = []\n\n    def add_rule(self, rule: AlertRule) -> None:\n        self._rules.append(rule)\n\n    def evaluate(self, metrics: dict[str, float]) -> list[dict]:\n        alerts = []\n        for rule in self._rules:\n            if not rule.enabled:\n                continue\n            value = metrics.get(rule.metric, 0)\n            if value > rule.threshold:\n                alert = {"rule": rule.name, "value": value, "threshold": rule.threshold, "severity": rule.severity.value}\n                alerts.append(alert)\n                self._fired.append(alert)\n        return alerts\n\n    @property\n    def total_fired(self) -> int:\n        return len(self._fired)\n',"feat(dashboard): add alert rules and threshold-based triggers"),
    (15,17,30,"tests/dashboard/test_alerts.py",'"""Tests for alert manager."""\nfrom bird_mach.dashboard.alerts import AlertManager, AlertRule, AlertSeverity\nclass TestAlertManager:\n    def test_no_alerts(self):\n        mgr = AlertManager()\n        mgr.add_rule(AlertRule("high_cpu", "cpu", 90.0, AlertSeverity.WARNING))\n        alerts = mgr.evaluate({"cpu": 50.0})\n        assert len(alerts) == 0\n    def test_fires_alert(self):\n        mgr = AlertManager()\n        mgr.add_rule(AlertRule("high_cpu", "cpu", 90.0, AlertSeverity.CRITICAL))\n        alerts = mgr.evaluate({"cpu": 95.0})\n        assert len(alerts) == 1\n        assert alerts[0]["severity"] == "critical"\n',"test(dashboard): add alert manager tests"),
    (15,18,0,"bird_mach/dashboard/leaderboard.py",'"""Usage leaderboard for gamification."""\nfrom __future__ import annotations\nfrom dataclasses import dataclass\n\n@dataclass\nclass LeaderboardEntry:\n    user_id: str\n    display_name: str\n    score: int\n    rank: int\n\nclass Leaderboard:\n    def __init__(self):\n        self._scores: dict[str, tuple[str, int]] = {}\n\n    def add_points(self, user_id: str, name: str, points: int) -> None:\n        current = self._scores.get(user_id, (name, 0))\n        self._scores[user_id] = (name, current[1] + points)\n\n    def get_top(self, n: int = 10) -> list[LeaderboardEntry]:\n        sorted_users = sorted(self._scores.items(), key=lambda x: -x[1][1])\n        return [\n            LeaderboardEntry(uid, name, score, rank+1)\n            for rank, (uid, (name, score)) in enumerate(sorted_users[:n])\n        ]\n\n    def get_rank(self, user_id: str) -> int | None:\n        for entry in self.get_top(len(self._scores)):\n            if entry.user_id == user_id:\n                return entry.rank\n        return None\n',"feat(dashboard): add usage leaderboard for gamification"),
