    (15,19,0,"bird_mach/tagging.py",'"""Audio tagging and labeling system."""\nfrom __future__ import annotations\nfrom collections import defaultdict\n\nclass TagManager:\n    """Manage tags across audio files and projects."""\n    def __init__(self):\n        self._tags: dict[str, set[str]] = defaultdict(set)\n        self._reverse: dict[str, set[str]] = defaultdict(set)\n\n    def tag(self, resource_id: str, tag: str) -> None:\n        self._tags[resource_id].add(tag)\n        self._reverse[tag].add(resource_id)\n\n    def untag(self, resource_id: str, tag: str) -> None:\n        self._tags[resource_id].discard(tag)\n        self._reverse[tag].discard(resource_id)\n\n    def get_tags(self, resource_id: str) -> set[str]:\n        return self._tags.get(resource_id, set())\n\n    def find_by_tag(self, tag: str) -> set[str]:\n        return self._reverse.get(tag, set())\n\n    def popular_tags(self, n: int = 10) -> list[tuple[str, int]]:\n        counts = [(tag, len(ids)) for tag, ids in self._reverse.items()]\n        counts.sort(key=lambda x: -x[1])\n        return counts[:n]\n',"feat: add audio tagging and labeling system"),
    (15,19,30,"tests/test_tagging.py",'"""Tests for tagging."""\nfrom bird_mach.tagging import TagManager\nclass TestTagManager:\n    def test_tag(self):\n        tm = TagManager()\n        tm.tag("a1", "jazz")\n        assert "jazz" in tm.get_tags("a1")\n    def test_find_by_tag(self):\n        tm = TagManager()\n        tm.tag("a1", "rock")\n        tm.tag("a2", "rock")\n        assert len(tm.find_by_tag("rock")) == 2\n    def test_untag(self):\n        tm = TagManager()\n        tm.tag("a1", "pop")\n        tm.untag("a1", "pop")\n        assert "pop" not in tm.get_tags("a1")\n    def test_popular(self):\n        tm = TagManager()\n        for i in range(5): tm.tag(f"a{i}", "common")\n        tm.tag("a0", "rare")\n        top = tm.popular_tags()\n        assert top[0][0] == "common"\n',"test: add tagging system tests — tag, find, untag, popular"),
    (15,20,0,"bird_mach/favorites.py",'"""Favorites and bookmarks for audio files."""\nfrom __future__ import annotations\nfrom collections import defaultdict\nfrom datetime import datetime\n\nclass FavoritesManager:\n    def __init__(self):\n        self._favorites: dict[str, dict[str, datetime]] = defaultdict(dict)\n\n    def add(self, user_id: str, audio_id: str) -> None:\n        self._favorites[user_id][audio_id] = datetime.now()\n\n    def remove(self, user_id: str, audio_id: str) -> None:\n        self._favorites[user_id].pop(audio_id, None)\n\n    def get(self, user_id: str) -> list[str]:\n        return sorted(self._favorites[user_id].keys(),\n                      key=lambda k: self._favorites[user_id][k], reverse=True)\n\n    def is_favorite(self, user_id: str, audio_id: str) -> bool:\n        return audio_id in self._favorites.get(user_id, {})\n\n    def count(self, user_id: str) -> int:\n        return len(self._favorites.get(user_id, {}))\n',"feat: add favorites/bookmarks manager for audio files"),
