    (15,22,0,"bird_mach/rate_limiter.py",'"""Token bucket rate limiter for API protection."""\nfrom __future__ import annotations\nimport time\nfrom dataclasses import dataclass\n\n@dataclass\nclass RateLimitResult:\n    allowed: bool\n    remaining: int\n    reset_at: float\n\nclass TokenBucketLimiter:\n    def __init__(self, capacity: int = 100, refill_rate: float = 10.0):\n        self._capacity = capacity\n        self._refill_rate = refill_rate\n        self._buckets: dict[str, tuple[float, float]] = {}\n\n    def check(self, key: str) -> RateLimitResult:\n        now = time.time()\n        tokens, last_refill = self._buckets.get(key, (float(self._capacity), now))\n        elapsed = now - last_refill\n        tokens = min(self._capacity, tokens + elapsed * self._refill_rate)\n        if tokens >= 1:\n            tokens -= 1\n            self._buckets[key] = (tokens, now)\n            return RateLimitResult(allowed=True, remaining=int(tokens), reset_at=now + (1/self._refill_rate))\n        self._buckets[key] = (tokens, now)\n        return RateLimitResult(allowed=False, remaining=0, reset_at=now + (1/self._refill_rate))\n',"feat: add token bucket rate limiter for API protection"),
    (15,22,30,"tests/test_rate_limiter.py",'"""Tests for rate limiter."""\nfrom bird_mach.rate_limiter import TokenBucketLimiter\nclass TestTokenBucket:\n    def test_allows_within_capacity(self):\n        rl = TokenBucketLimiter(capacity=10)\n        result = rl.check("user1")\n        assert result.allowed\n        assert result.remaining == 9\n    def test_exhaustion(self):\n        rl = TokenBucketLimiter(capacity=2, refill_rate=0.001)\n        rl.check("u1")\n        rl.check("u1")\n        result = rl.check("u1")\n        assert not result.allowed\n',"test: add token bucket rate limiter tests"),
